def median_ops(operations):
    import heapq

    class MedianFinder:
        def __init__(self):
            self.lo = []  # max-heap via negation: holds the smaller half
            self.hi = []  # min-heap: holds the larger half

        def addNum(self, num):
            heapq.heappush(self.lo, -num)
            heapq.heappush(self.hi, -heapq.heappop(self.lo))
            if len(self.hi) > len(self.lo):
                heapq.heappush(self.lo, -heapq.heappop(self.hi))

        def findMedian(self):
            if len(self.lo) > len(self.hi):
                return float(-self.lo[0])
            return (-self.lo[0] + self.hi[0]) / 2.0

    results = []
    mf = None
    for op in operations:
        method, args = op[0], op[1:]
        if method == "MedianFinder":
            mf = MedianFinder()
            results.append(None)
        elif method == "addNum":
            mf.addNum(*args)
            results.append(None)
        elif method == "findMedian":
            results.append(mf.findMedian())
    return results
